# SECTOR ROTATION ANALYSIS ENGINE
# =====================================================================

_SECTOR_TICKERS = [
    {"name": "NIFTY BANK",    "yf": "^NSEBANK",  "sector": "Banking"},
    {"name": "NIFTY IT",      "yf": "^CNXIT",    "sector": "IT"},
    {"name": "NIFTY AUTO",    "yf": "^CNXAUTO",  "sector": "Auto"},
    {"name": "NIFTY FMCG",    "yf": "^CNXFMCG",  "sector": "FMCG"},
    {"name": "NIFTY PHARMA",  "yf": "^CNXPHARMA","sector": "Pharma"},
    {"name": "NIFTY METAL",   "yf": "^CNXMETAL", "sector": "Metal"},
    {"name": "NIFTY ENERGY",  "yf": "^CNXENERGY","sector": "Energy"},
    {"name": "NIFTY REALTY",  "yf": "^CNXREALTY","sector": "Realty"},
    {"name": "NIFTY PSU BANK","yf": "^CNXPSUBANK","sector": "PSU Bank"},
]

@st.cache_data(ttl=300)
def _sre_fetch_all():
    """Fetch 3-month daily data for all sector indices via yfinance."""
    if not _YF_AVAILABLE:
        return {}
    import yfinance as yf
    results = {}
    tickers = [t["yf"] for t in _SECTOR_TICKERS]
    try:
        raw = yf.download(tickers, period="3mo", interval="1d",
                          group_by="ticker", auto_adjust=True, progress=False)
        for t_info in _SECTOR_TICKERS:
            sym = t_info["yf"]
            try:
                if len(tickers) == 1:
                    df_sym = raw.copy()
                else:
                    df_sym = raw[sym].copy() if sym in raw.columns.get_level_values(0) else pd.DataFrame()
                df_sym.columns = [c.lower() for c in df_sym.columns]
                df_sym = df_sym.dropna(subset=["close"])
                results[sym] = df_sym
            except Exception:
                results[sym] = pd.DataFrame()
    except Exception:
        pass
    return results

def _sre_momentum(close_series, period):
    if len(close_series) < period + 1:
        return np.nan
    return (close_series.iloc[-1] / close_series.iloc[-period] - 1) * 100

def _sre_rs_ratio(sector_close, bench_close):
    """Relative strength ratio of sector vs benchmark."""
    s = sector_close.reindex(bench_close.index, method='ffill').dropna()
    b = bench_close.reindex(s.index).dropna()
    idx = s.index.intersection(b.index)
    if len(idx) < 2:
        return np.nan
    return (s.loc[idx].iloc[-1] / b.loc[idx].iloc[-1]) * 100

def _sre_rotation_phase(rs_ratio_vals):
    """
    JdK RS-Ratio + RS-Momentum simplified:
    Leading (RS>100, RS rising), Weakening (RS>100, RS falling),
    Lagging (RS<100, RS falling), Improving (RS<100, RS rising)
    """
    if len(rs_ratio_vals) < 2 or any(np.isnan(v) for v in rs_ratio_vals[-2:]):
        return "UNKNOWN"
    curr, prev = rs_ratio_vals[-1], rs_ratio_vals[-2]
    rising = curr > prev
    if curr >= 100 and rising:
        return "LEADING"
    elif curr >= 100 and not rising:
        return "WEAKENING"
    elif curr < 100 and not rising:
        return "LAGGING"
    else:
        return "IMPROVING"

def show_sector_rotation_engine():
    """14-Module Sector Rotation Analysis Engine."""
    st.markdown("### 🔄 Sector Rotation Analysis Engine — NSE India")

    if not _YF_AVAILABLE:
        st.warning("yfinance not available. Install it (requirements.txt) to enable this engine.")
        return

    with st.spinner("Fetching sector data..."):
        sector_data = _sre_fetch_all()

    if not sector_data:
        st.error("❌ Live sector data unavailable (network/yfinance). Please try again later.")
        return

    # Get NIFTY50 as benchmark
    import yfinance as yf
    try:
        bench_raw = yf.download("^NSEI", period="3mo", interval="1d",
                                auto_adjust=True, progress=False)
        bench_raw.columns = [c.lower() if isinstance(c, str) else c for c in bench_raw.columns]
        if isinstance(bench_raw.columns, pd.MultiIndex):
            bench_raw.columns = [c[0].lower() for c in bench_raw.columns]
        bench_close = bench_raw['close'].dropna() if 'close' in bench_raw.columns else pd.Series(dtype=float)
    except Exception:
        bench_close = pd.Series(dtype=float)

    rows = []
    rs_history = {}

    for t_info in _SECTOR_TICKERS:
        sym  = t_info["yf"]
        name = t_info["name"]
        df_s = sector_data.get(sym, pd.DataFrame())

        if df_s.empty or 'close' not in df_s.columns or len(df_s) < 5:
            rows.append({
                "Sector": name, "LTP": "N/A", "1D%": "N/A", "1W%": "N/A",
                "1M%": "N/A", "3M%": "N/A", "RS vs NIFTY": "N/A",
                "Phase": "UNKNOWN", "Signal": "N/A", "Strength": "N/A",
                "_chg1d_raw": 0.0, "_chg1w_raw": 0.0,
                "_phase_raw": "UNKNOWN", "_signal_raw": "N/A",
            })
            continue

        cl = df_s['close']
        ltp = cl.iloc[-1]
        chg_1d = _sre_momentum(cl, 1)
        chg_1w = _sre_momentum(cl, 5)
        chg_1m = _sre_momentum(cl, 21)
        chg_3m = _sre_momentum(cl, 63)

        # Relative strength
        rs_val = _sre_rs_ratio(cl, bench_close) if not bench_close.empty else np.nan

        # Build rolling RS for phase detection (last 5 daily values)
        rs_series = []
        if not bench_close.empty:
            for i in range(min(5, len(cl))):
                idx_offset = -(i+1)
                s_slice = cl.iloc[:len(cl)+idx_offset] if idx_offset < 0 else cl
                b_slice = bench_close.iloc[:len(bench_close)+idx_offset] if idx_offset < 0 else bench_close
                rs_series.insert(0, _sre_rs_ratio(s_slice, b_slice))
        rs_history[sym] = rs_series

        phase = _sre_rotation_phase(rs_series) if rs_series else "UNKNOWN"

        # Signal based on phase + momentum
        if phase == "LEADING" and chg_1w > 0:
            signal = "OVERWEIGHT"
        elif phase == "WEAKENING":
            signal = "REDUCE"
        elif phase == "LAGGING":
            signal = "UNDERWEIGHT"
        elif phase == "IMPROVING" and chg_1d > 0:
            signal = "ACCUMULATE"
        else:
            signal = "NEUTRAL"

        # Strength score (0-100)
        score_parts = [
            min(max(chg_1d * 10 + 50, 0), 100) if not np.isnan(chg_1d) else 50,
            min(max(chg_1w * 5  + 50, 0), 100) if not np.isnan(chg_1w) else 50,
            min(max(chg_1m * 2  + 50, 0), 100) if not np.isnan(chg_1m) else 50,
        ]
        strength = int(np.mean(score_parts))

        rows.append({
            "Sector":      name,
            "LTP":         f"{ltp:,.0f}",
            "1D%":         f"{chg_1d:+.2f}%" if not np.isnan(chg_1d) else "N/A",
            "1W%":         f"{chg_1w:+.2f}%" if not np.isnan(chg_1w) else "N/A",
            "1M%":         f"{chg_1m:+.2f}%" if not np.isnan(chg_1m) else "N/A",
            "3M%":         f"{chg_3m:+.2f}%" if not np.isnan(chg_3m) else "N/A",
            "RS vs NIFTY": f"{rs_val:.1f}" if not np.isnan(rs_val) else "N/A",
            "Phase":       phase,
            "Signal":      signal,
            "Strength":    strength,
            "_chg1d_raw":  chg_1d if not np.isnan(chg_1d) else 0,
            "_chg1w_raw":  chg_1w if not np.isnan(chg_1w) else 0,
            "_phase_raw":  phase,
            "_signal_raw": signal,
        })

    if not rows:
        st.warning("No sector data available.")
        return

    full_df = pd.DataFrame(rows)
    display_cols = ["Sector","LTP","1D%","1W%","1M%","3M%","RS vs NIFTY","Phase","Signal","Strength"]
    disp_df = full_df[display_cols].copy()

    # ── MODULE 2: Heatmap-style styling ──────────────────────────────
    def _sre_style_row(row):
        styles = [""] * len(row)
        phase  = str(row.get("Phase", ""))
        signal = str(row.get("Signal", ""))
        phase_colors = {
            "LEADING":   ("background-color:#1a3a1a", "color:#00e676"),
            "IMPROVING": ("background-color:#1a2a3a", "color:#40c4ff"),
            "WEAKENING": ("background-color:#2a2a1a", "color:#ffeb3b"),
            "LAGGING":   ("background-color:#3a1a1a", "color:#ff5252"),
        }
        sig_colors = {
            "OVERWEIGHT":  "color:#00e676; font-weight:bold",
            "ACCUMULATE":  "color:#40c4ff; font-weight:bold",
            "NEUTRAL":     "color:#bdbdbd",
            "REDUCE":      "color:#ffeb3b; font-weight:bold",
            "UNDERWEIGHT": "color:#ff5252; font-weight:bold",
        }
        col_names = list(row.index)
        for i, col in enumerate(col_names):
            if col == "Phase":
                bg, fg = phase_colors.get(phase, ("", ""))
                styles[i] = f"{bg}; {fg}"
            elif col == "Signal":
                styles[i] = sig_colors.get(signal, "")
            elif col in ("1D%", "1W%", "1M%", "3M%"):
                try:
                    val = float(str(row[col]).replace("%","").replace("+",""))
                    if val > 1:
                        styles[i] = "color:#00e676"
                    elif val < -1:
                        styles[i] = "color:#ff5252"
                    else:
                        styles[i] = "color:#bdbdbd"
                except Exception:
                    pass
        return styles

    # ── MODULE 10: Dashboard Table ────────────────────────────────────
    st.markdown("#### 📊 Sector Rotation Table")
    st.dataframe(
        disp_df.style.apply(_sre_style_row, axis=1),
        use_container_width=True, hide_index=True
    )

    # ── MODULE 3: Money Flow Heatmap ──────────────────────────────────
    st.markdown("#### 💹 Money Flow Heatmap (1W Performance)")
    heat_data = []
    for r in rows:
        try:
            pct = float(str(r["1W%"]).replace("%","").replace("+",""))
        except Exception:
            pct = 0
        heat_data.append({"Sector": r["Sector"], "1W%": pct})
    heat_df = pd.DataFrame(heat_data).sort_values("1W%", ascending=False)

    def _heat_color(val):
        if val > 2:    return "background-color:#00600a; color:white"
        elif val > 0:  return "background-color:#1b5e20; color:#e8f5e9"
        elif val > -2: return "background-color:#b71c1c; color:#ffcdd2"
        else:          return "background-color:#7f0000; color:white"

    st.dataframe(
        heat_df.style.map(_heat_color, subset=["1W%"]),
        use_container_width=True, hide_index=True
    )

    # ── MODULE 4: Relative Strength Rankings ─────────────────────────
    st.markdown("#### 🏆 Relative Strength Rankings (vs NIFTY 50)")
    rs_rows = []
    for r in rows:
        rs_val_str = r.get("RS vs NIFTY", "N/A")
        try:
            rs_num = float(rs_val_str)
        except Exception:
            rs_num = np.nan
        phase = r.get("Phase", "UNKNOWN")
        rs_rows.append({
            "Sector": r["Sector"],
            "RS Ratio": rs_val_str,
            "Phase": phase,
            "Rank Signal": "OUTPERFORM" if (not np.isnan(rs_num) and rs_num >= 100) else "UNDERPERFORM"
        })
    rs_df = pd.DataFrame(rs_rows)

    def _rs_style(row):
        if row["Rank Signal"] == "OUTPERFORM":
            return [""] + ["background-color:#1a3a1a; color:#00e676"] * (len(row)-1)
        return [""] + ["background-color:#3a1a1a; color:#ff5252"] * (len(row)-1)

    st.dataframe(rs_df.style.apply(_rs_style, axis=1), use_container_width=True, hide_index=True)

    # ── MODULE 5: Rotation Signals Summary ───────────────────────────
    leading   = [r["Sector"] for r in rows if r["Phase"] == "LEADING"]
    improving = [r["Sector"] for r in rows if r["Phase"] == "IMPROVING"]
    weakening = [r["Sector"] for r in rows if r["Phase"] == "WEAKENING"]
    lagging   = [r["Sector"] for r in rows if r["Phase"] == "LAGGING"]

    st.markdown("#### 🔄 Rotation Phase Summary")
    rc1, rc2, rc3, rc4 = st.columns(4)
    with rc1:
        st.success(f"**LEADING** ({len(leading)})\n\n" + "\n".join(f"• {s}" for s in leading) if leading else "None")
    with rc2:
        st.info(f"**IMPROVING** ({len(improving)})\n\n" + "\n".join(f"• {s}" for s in improving) if improving else "None")
    with rc3:
        st.warning(f"**WEAKENING** ({len(weakening)})\n\n" + "\n".join(f"• {s}" for s in weakening) if weakening else "None")
    with rc4:
        st.error(f"**LAGGING** ({len(lagging)})\n\n" + "\n".join(f"• {s}" for s in lagging) if lagging else "None")

    # ── MODULE 6: Intraday Tracker (1D momentum rankings) ────────────
    with st.expander("⚡ Intraday Sector Momentum Tracker", expanded=False):
        intra_rows = sorted(rows, key=lambda x: x["_chg1d_raw"], reverse=True)
        intra_df = pd.DataFrame([
            {"Rank": i+1, "Sector": r["Sector"], "1D Change": r["1D%"], "Signal": r["Signal"]}
            for i, r in enumerate(intra_rows)
        ])

        def _intra_style(row):
            try:
                val = float(str(row["1D Change"]).replace("%","").replace("+",""))
                c = "color:#00e676" if val > 0 else "color:#ff5252"
            except Exception:
                c = ""
            return ["", "", c, ""]
        st.dataframe(intra_df.style.apply(_intra_style, axis=1), use_container_width=True, hide_index=True)

    # ── MODULE 7: Alerts ──────────────────────────────────────────────
    st.markdown("#### 🚨 Sector Rotation Alerts")
    sector_alerts = []
    for r in rows:
        if r["Phase"] == "IMPROVING" and r["_chg1w_raw"] > 2:
            sector_alerts.append(f"🟢 **{r['Sector']}** entering IMPROVING phase with strong 1W gain ({r['1W%']})")
        if r["Phase"] == "WEAKENING" and r["_chg1w_raw"] < -1:
            sector_alerts.append(f"🟡 **{r['Sector']}** WEAKENING — consider reducing exposure ({r['1W%']})")
        if r["Phase"] == "LAGGING" and r["_chg1d_raw"] < -1.5:
            sector_alerts.append(f"🔴 **{r['Sector']}** LAGGING with today's drop ({r['1D%']}) — avoid")
        if r["Phase"] == "LEADING" and r["_chg1w_raw"] > 3:
            sector_alerts.append(f"⚡ **{r['Sector']}** LEADING strongly ({r['1W%']} in 1W) — momentum play")

    if sector_alerts:
        for al in sector_alerts:
            st.info(al)
    else:
        st.success("✅ No critical sector rotation alerts at this time.")


# =====================================================================
# INTRADAY SECTOR ROTATION ENGINE
# =====================================================================

_INTRA_SECTORS = [
    {"name": "NIFTY BANK",    "yf": "^NSEBANK",   "weight": 3},
    {"name": "NIFTY IT",      "yf": "^CNXIT",     "weight": 2},
    {"name": "NIFTY AUTO",    "yf": "^CNXAUTO",   "weight": 2},
    {"name": "NIFTY FMCG",   "yf": "^CNXFMCG",   "weight": 1},
    {"name": "NIFTY PHARMA", "yf": "^CNXPHARMA",  "weight": 1},
    {"name": "NIFTY METAL",  "yf": "^CNXMETAL",   "weight": 1},
    {"name": "NIFTY ENERGY", "yf": "^CNXENERGY",  "weight": 2},
    {"name": "PSU BANK",     "yf": "^CNXPSUBANK", "weight": 1},
    {"name": "NIFTY REALTY", "yf": "^CNXREALTY",  "weight": 1},
]
_INTRA_BENCH = "^NSEI"

@st.cache_data(ttl=180)
def _intra_fetch_all():
    """Fetch 2-day 5m data for sectors + NIFTY50 benchmark."""
    if not _YF_AVAILABLE:
        return {}
    import yfinance as yf
    tickers = [s["yf"] for s in _INTRA_SECTORS] + [_INTRA_BENCH]
    out = {}
    try:
        raw = yf.download(
            tickers, period="2d", interval="5m",
            auto_adjust=True, progress=False
        )
        if not raw.empty and isinstance(raw.columns, pd.MultiIndex):
            lvl0 = list(raw.columns.get_level_values(0).unique())
            lvl1 = list(raw.columns.get_level_values(1).unique())
            for sym in tickers:
                try:
                    if sym in lvl0:
                        # Old format: (ticker, field)
                        df_s = raw[sym].copy()
                    elif sym in lvl1:
                        # New yfinance format: (field, ticker)
                        df_s = raw.xs(sym, axis=1, level=1).copy()
                    else:
                        out[sym] = pd.DataFrame()
                        continue
                    df_s.columns = [c.lower() for c in df_s.columns]
                    df_s = df_s.dropna(subset=["close"])
                    out[sym] = df_s
                except Exception:
                    out[sym] = pd.DataFrame()
        elif not raw.empty:
            df_s = raw.copy()
            df_s.columns = [c.lower() for c in df_s.columns]
            df_s = df_s.dropna(subset=["close"])
            out[tickers[0]] = df_s
    except Exception:
        pass
    # Fallback: fetch individually for any missing tickers
    for sym in tickers:
        if sym not in out or out[sym].empty:
            try:
                df_s = yf.download(sym, period="2d", interval="5m",
                                   auto_adjust=True, progress=False)
                if not df_s.empty:
                    df_s.columns = [c.lower() for c in df_s.columns]
                    df_s = df_s.dropna(subset=["close"])
                    out[sym] = df_s
                else:
                    out[sym] = pd.DataFrame()
            except Exception:
                out[sym] = pd.DataFrame()
    return out

def _intra_momentum(cl: pd.Series, bars: int) -> float:
    if len(cl) < bars + 1:
        return np.nan
    return (cl.iloc[-1] / cl.iloc[-bars - 1] - 1) * 100

def _intra_phase(rs_ratio: float, rs_slope: float,
                 mom5: float, mom15: float, mom1h: float) -> str:
    if rs_ratio > 100 and rs_slope > 0 and mom15 > 0 and mom1h > 0:
        return "LEADING"
    if rs_ratio < 100 and rs_slope > 0 and mom5 > 0:
        return "IMPROVING"
    if rs_ratio > 100 and rs_slope < 0 and mom5 < 0:
        return "WEAKENING"
    if rs_ratio < 100 and rs_slope < 0 and mom15 < 0:
        return "LAGGING"
    return "NEUTRAL"

def _intra_sector_score(mom5: float, mom15: float, mom1h: float) -> float:
    """Sector_Score = mom5×0.35 + mom15×0.35 + mom1h×0.30, normalised 0–100."""
    raw = mom5 * 0.35 + mom15 * 0.35 + mom1h * 0.30
    # Sigmoid-style map: raw ±2% → 0–100
    return max(0.0, min(100.0, 50 + raw * 12.5))

def show_intraday_sector_rotation():
    """Intraday Sector Rotation Engine — 5m/15m/1h RS and phase detection."""
    st.markdown("### ⚡ Sector Rotation Engine — Intraday Version")

    if not _YF_AVAILABLE:
        st.warning("yfinance required. Check requirements.txt.")
        return

    with st.spinner("Fetching intraday sector data (5m)..."):
        data = _intra_fetch_all()

    if not data:
        st.error("❌ Live intraday sector data unavailable (network/yfinance). Please try again later.")
        return

    bench_df = data.get(_INTRA_BENCH, pd.DataFrame())
    if bench_df.empty or "close" not in bench_df.columns:
        st.error("❌ NIFTY 50 benchmark intraday data unavailable. Please try again later.")
        return

    bench_cl = bench_df["close"]
    bench_now = bench_cl.iloc[-1]
    # bars for each window (5m data): 5m=1, 15m=3, 1h=12
    B5, B15, B1H = 1, 3, 12

    rows = []
    prev_leaders_key = "intra_prev_leaders"
    if prev_leaders_key not in st.session_state:
        st.session_state[prev_leaders_key] = []

    for sec in _INTRA_SECTORS:
        sym   = sec["yf"]
        name  = sec["name"]
        df_s  = data.get(sym, pd.DataFrame())

        if df_s.empty or "close" not in df_s.columns or len(df_s) < 2:
            continue  # Skip sectors with no live data

        cl = df_s["close"]
        now_price = cl.iloc[-1]

        # RS Ratio
        bench_aligned = bench_cl.reindex(cl.index, method="ffill").dropna()
        cl_aligned = cl.reindex(bench_aligned.index).dropna()
        idx = cl_aligned.index.intersection(bench_aligned.index)
        rs = (cl_aligned.loc[idx].iloc[-1] / bench_aligned.loc[idx].iloc[-1] * 100) \
            if len(idx) > 0 else 100.0

        # RS Slope (current vs 3 bars ago)
        if len(idx) >= 4:
            rs_prev = (cl_aligned.loc[idx].iloc[-4] / bench_aligned.loc[idx].iloc[-4] * 100)
        else:
            rs_prev = rs
        rs_slope = rs - rs_prev

        # Momentum windows
        mom5  = _intra_momentum(cl, B5)
        mom15 = _intra_momentum(cl, B15)
        mom1h = _intra_momentum(cl, B1H)

        def _safe(v): return 0.0 if (v is None or (isinstance(v, float) and np.isnan(v))) else v
        m5, m15, m1h = _safe(mom5), _safe(mom15), _safe(mom1h)

        phase = _intra_phase(rs, rs_slope, m5, m15, m1h)
        score = _intra_sector_score(m5, m15, m1h)

        def _fmt(v):
            return f"{v:+.2f}%" if not (v is None or (isinstance(v, float) and np.isnan(v))) else "N/A"

        rows.append({
            "Sector":        name,
            "RS Ratio":      f"{rs:.1f}",
            "Momentum 5m":   _fmt(mom5),
            "Momentum 15m":  _fmt(mom15),
            "Momentum 1h":   _fmt(mom1h),
            "Phase":         phase,
            "Strength Score":int(score),
            "Rotation Signal": "—",
            "_raw_score":    score,
            "_phase":        phase,
            "_mom5":         m5,
            "_mom15":        m15,
            "_rs":           rs,
        })

    # Sort by score
    rows_sorted = sorted(rows, key=lambda x: x["_raw_score"], reverse=True)

    # ── Module 6+7: Leadership & Rotation Detection ──────────────────
    top3   = [r["Sector"] for r in rows_sorted[:3]]
    bot3   = [r["Sector"] for r in rows_sorted[-3:]]
    prev_l = st.session_state.get(prev_leaders_key, [])
    rotation_alerts = []

    for r in rows_sorted:
        if r["Sector"] in top3:
            r["Rotation Signal"] = "⭐ LEADER"
        elif r["Sector"] in bot3:
            r["Rotation Signal"] = "⚠️ WEAK"

    # Detect rotation: previous leader now not in top3
    if prev_l:
        for old_lead in prev_l:
            if old_lead not in top3:
                new_lead = top3[0] if top3 else "Unknown"
                rotation_alerts.append(
                    f"🔄 **ROTATION ALERT**: Money rotating from **{old_lead}** → **{new_lead}**"
                )
    st.session_state[prev_leaders_key] = top3

    # ── Module 8: Market Bias ─────────────────────────────────────────
    leading_count  = sum(1 for r in rows if r["_phase"] == "LEADING")
    lagging_count  = sum(1 for r in rows if r["_phase"] == "LAGGING")
    heavy_leading  = sum(1 for r in rows_sorted[:3] if r["_phase"] == "LEADING")
    if heavy_leading >= 2:
        mkt_bias, bias_color = "BULLISH", "#00e676"
    elif lagging_count >= 5:
        mkt_bias, bias_color = "BEARISH", "#ff5252"
    else:
        mkt_bias, bias_color = "RANGE / NEUTRAL", "#ffeb3b"

    # ── KPI strip ────────────────────────────────────────────────────
    kc1, kc2, kc3, kc4 = st.columns(4)
    with kc1:
        st.markdown(
            f"<div style='padding:10px;background:#1e1e1e;border-radius:8px;"
            f"border-left:4px solid {bias_color};'>"
            f"<span style='font-size:11px;color:#aaa'>Market Bias</span><br>"
            f"<span style='font-size:20px;font-weight:bold;color:{bias_color}'>{mkt_bias}</span>"
            f"</div>", unsafe_allow_html=True)
    with kc2:
        st.metric("Leading Sectors", leading_count)
    with kc3:
        st.metric("Top Leader", top3[0] if top3 else "—")
    with kc4:
        st.metric("Weakest Sector", bot3[-1] if bot3 else "—")

    # ── Module 9: Dashboard Table ─────────────────────────────────────
    st.markdown("#### 📊 Intraday Sector Dashboard")
    _PHASE_STYLES = {
        "LEADING":   "background-color:#1a3a1a; color:#00e676; font-weight:bold",
        "IMPROVING": "background-color:#1a2a3a; color:#40c4ff; font-weight:bold",
        "WEAKENING": "background-color:#2a2a1a; color:#ffeb3b; font-weight:bold",
        "LAGGING":   "background-color:#3a1a1a; color:#ff5252; font-weight:bold",
        "NEUTRAL":   "color:#bdbdbd",
        "UNKNOWN":   "color:#757575",
    }

    disp_cols = ["Sector","RS Ratio","Momentum 5m","Momentum 15m",
                 "Momentum 1h","Phase","Strength Score","Rotation Signal"]
    disp_df = pd.DataFrame([{c: r[c] for c in disp_cols} for r in rows_sorted])

    def _intra_style(row):
        styles = [""] * len(row)
        col_names = list(row.index)
        phase = str(row.get("Phase", ""))
        for i, col in enumerate(col_names):
            if col == "Phase":
                styles[i] = _PHASE_STYLES.get(phase, "")
            elif col == "Strength Score":
                score_v = int(row[col]) if str(row[col]).isdigit() else 50
                if score_v >= 65:   styles[i] = "color:#00e676; font-weight:bold"
                elif score_v >= 55: styles[i] = "color:#69f0ae"
                elif score_v <= 35: styles[i] = "color:#ff5252; font-weight:bold"
                elif score_v <= 45: styles[i] = "color:#ff8a80"
                else:               styles[i] = "color:#bdbdbd"
            elif col in ("Momentum 5m","Momentum 15m","Momentum 1h"):
                try:
                    v = float(str(row[col]).replace("%","").replace("+",""))
                    styles[i] = "color:#00e676" if v > 0 else ("color:#ff5252" if v < 0 else "")
                except Exception:
                    pass
            elif col == "Rotation Signal" and "LEADER" in str(row[col]):
                styles[i] = "color:#ffd700; font-weight:bold"
            elif col == "Rotation Signal" and "WEAK" in str(row[col]):
                styles[i] = "color:#ff8a80"
        return styles

    st.dataframe(
        disp_df.style.apply(_intra_style, axis=1),
        use_container_width=True, hide_index=True, height=380
    )

    # ── Phase Summary ─────────────────────────────────────────────────
    st.markdown("#### 🔄 Intraday Phase Distribution")
    pc1, pc2, pc3, pc4 = st.columns(4)
    with pc1:
        leading_list = [r["Sector"] for r in rows if r["_phase"]=="LEADING"]
        st.success(f"**LEADING** ({len(leading_list)})\n\n" + "\n".join(f"• {s}" for s in leading_list) if leading_list else "None")
    with pc2:
        improving_list = [r["Sector"] for r in rows if r["_phase"]=="IMPROVING"]
        st.info(f"**IMPROVING** ({len(improving_list)})\n\n" + "\n".join(f"• {s}" for s in improving_list) if improving_list else "None")
    with pc3:
        weakening_list = [r["Sector"] for r in rows if r["_phase"]=="WEAKENING"]
        st.warning(f"**WEAKENING** ({len(weakening_list)})\n\n" + "\n".join(f"• {s}" for s in weakening_list) if weakening_list else "None")
    with pc4:
        lagging_list = [r["Sector"] for r in rows if r["_phase"]=="LAGGING"]
        st.error(f"**LAGGING** ({len(lagging_list)})\n\n" + "\n".join(f"• {s}" for s in lagging_list) if lagging_list else "None")

    # Rotation alerts
    if rotation_alerts:
        st.markdown("#### 🚨 Rotation Alerts")
        for a in rotation_alerts:
            st.warning(a)


