                                        f"{_gamma_str}\n"
                                        f"{_oi_str}\n"
                                        f"Straddle: {'Expanding ✅' if _opt.get('straddle_expanding') else 'Flat'}\n"
                                        f"Confidence: {_conf}/100 — {_strength}"
